{!REQUIRESCRIPT("/soap/ajax/33.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/33.0/apex.js")}

var ppCount = '{!Contact.IP_PAYECount__c}';

result = sforce.connection.query("SELECT IP_LastPassedToTempest__c  FROM IP_PayProfile__c WHERE IP_Candidate__c= '{!Contact.Id}' and IP_Status__c ='Active' and RecordType.Name='PAYE'");
records = result.getArray("records"); 


if(ppCount>0 && records.length>0)
{
	var P45_Date = '{!Contact.IP_WorkerLeavingDate__c}';
	var P45_Requested = '{!Contact.P45_Requested__c}';
	var P45_HeadOfficeDate = '{!Contact.P45_Date_by_Head_Office__c}';


	if(records[0].IP_LastPassedToTempest__c==null)
	{
		alert('Candidate has never worked and has no historic or active timesheet/s associated.');
	}
	else if(P45_HeadOfficeDate==0)
	{
		window.open('/apex/RequestP45Page?id={! Contact.Id}', '_blank', 'height=550,width=800,resizable=yes,scrollbars=yes,toolbar=n??o,menubar=no');
	}
	else
	{
		alert('P45 process has been initiated already');
	}
}
else
{
	alert('No Paye profile for this candidate');
}
